server.on('error', (err) => { console.error('Failed to start:', err); process.exit(1); });
```

## 3. No input validation

Neither endpoint currently takes input, but as soon as you add query/body parameters you'll want validation in place. Adopt a schema validator up front:

```js
const { z } = require('zod');

const UserQuery = z.object({
  id: z.coerce.number().int().positive().optional(),
  limit: z.coerce.number().int().min(1).max(100).default(20),
});

app.get('/users', (req, res, next) => {
  const parsed = UserQuery.safeParse(req.query);
  if (!parsed.success) return res.status(400).json({ error: parsed.error.flatten() });
  // ...use parsed.data
});
```

