app.use(cors({ origin: ALLOWED_ORIGINS }));  // explicit allowlist, not '*'
app.use(express.json({ limit: '100kb' })); // cap body size to prevent DoS
app.use(rateLimit({ windowMs: 60_000, max: 100 })); // basic abuse protection
app.disable('x-powered-by');             // don't advertise Express
